scwin.f_Create = async function() {
    if(ds_crn.getInsertedIndex().length > 0) {
        let ret = await scwin.f_Validation();
        if(!ret) {
            return false;
        }
    }
    let row = ds_crn.insertRow();
    gr_crn.setFocusedCell(row, 0, false);

    scwin.addCountRow = ds_crn.getRowCount();
    $c.gus.cfEnableKeyData();
    $c.gus.cfEnableObjects([btn_zip, ica_quitDt, btn_busiZip]);
    // $c.gus.cfDisableObjects([ed_zip, ed_addr1, ed_busiZip, ed_busiAddr1, lc_etcBusiClsCd]);
    $c.gus.cfDisableObjects([ed_zip, ed_addr1, ed_busiZip, ed_busiAddr1, lc_etcBusiClsCd, ica_quitDt]); //폐업여부 추가
    $c.gus.cfDisableBtn([btn_update, btn_create]);
    lc_busiClsCd.focus();

    lc_crGrdClsCd.setValue("02");       //신용등급관리구분(저장) : 미등록(02)
    lc_intrlns.setValue("0");           //계열구분(저장) : 비계열(0)
    cbx_mailSendYn.setValue("1");       //메일발송여부

    if (scwin.gJudgeYn == "0") {
        $c.gus.cfDisableObjects([cbx_crdtExceptTrgtYn, lc_crdtExceptTrgtCls, cbx_prvsSzYn, cbx_setoffExceptTrgtYn, cbx_mailSendYn, cbx_nonDeductYn]);
        $c.gus.cfDisableObjects([cbx_collMoneyRuleAdptYn]);
    } else if (scwin.gJudgeYn == "1") {
        $c.gus.cfEnableObjects([cbx_crdtExceptTrgtYn, lc_crdtExceptTrgtCls, cbx_prvsSzYn, cbx_setoffExceptTrgtYn, cbx_mailSendYn, cbx_nonDeductYn]);
    } else {
        $c.gus.cfDisableObjects([cbx_crdtExceptTrgtYn, lc_crdtExceptTrgtCls, cbx_prvsSzYn, cbx_setoffExceptTrgtYn, cbx_mailSendYn, cbx_nonDeductYn]);
        $c.gus.cfDisableObjects([cbx_collMoneyRuleAdptYn]);
    }

    if (scwin.gElecApprvChk == "Y") {
        $c.gus.cfEnableObjects([cbx_elecApprvChkYn]);
    } else if (scwin.gElecApprvChk == "N") {
        $c.gus.cfDisableObjects([cbx_elecApprvChkYn]);
    } else {
        $c.gus.cfDisableObjects([cbx_elecApprvChkYn]);
    }
    //실명인증 결과값 초기화
    scwin.gNameCheck = 0;
    scwin.oldjumin = "";
};


