    //폐업여부 체크 있으면 폐업일자 활성화
    if(cbx_quitYn.getValue() == "1") {
        $c.gus.cfEnableObjects([ica_quitDt]);
    }else {
        $c.gus.cfDisableObjects([ica_quitDt]);        
