        $c.gus.cfEnableObjects([ed_corRegNo]);
    }
    //spy
    if (lc_busiClsCd.getValue() == "2") {
        lbl_val.setValue("생년월일+성별");
    } else {
        lbl_val.setValue("법인번호/이미지첨부");
    }

    //focus 설정
    ed_busiNm.focus();

    if (scwin.gJudgeYn == "0") {
        $c.gus.cfDisableObjects([cbx_crdtExceptTrgtYn, lc_crdtExceptTrgtCls, lc_busiClsCd, cbx_prvsSzYn, cbx_setoffExceptTrgtYn, cbx_mailSendYn, cbx_nonDeductYn]);
        $c.gus.cfDisableObjects([cbx_collMoneyRuleAdptYn]);
    } else if (scwin.gJudgeYn == "1") {
        $c.gus.cfEnableObjects([cbx_crdtExceptTrgtYn, lc_crdtExceptTrgtCls, lc_busiClsCd, cbx_prvsSzYn, cbx_setoffExceptTrgtYn, cbx_mailSendYn, cbx_nonDeductYn]);
        $c.gus.cfEnableObjects([cbx_collMoneyRuleAdptYn]);
    }

    if (lc_busiClsCd.getValue() == "4") {
        $c.gus.cfEnableObjects([lc_etcBusiClsCd]);
        lc_etcBusiClsCd.setMandatory(true);
        lbl_etcBusiClsCd.addClass("req");
        lc_taxnCls.setMandatory(false); 
        lbl_taxnCls.removeClass("req");
    }

    if (scwin.gElecApprvChk == "Y") {
        $c.gus.cfEnableObjects([cbx_elecApprvChkYn]);
    } else if (scwin.gElecApprvChk == "N") {
        $c.gus.cfDisableObjects([cbx_elecApprvChkYn]);
    } else {
        $c.gus.cfDisableObjects([cbx_elecApprvChkYn]);
    }

    //영수매출인 경우
    if (cbx_receiveSellingYn.getValue() == "1") {
        //$c.gus.cfDisableObjects([btn_corRegNo]);
        ed_corRegNo.setMandatory(false);
        lbl_val.removeClass("req");
    } else {
        //$c.gus.cfEnableObjects([btn_corRegNo]);
    }

    if (lc_busiClsCd.getValue() == "1" || lc_busiClsCd.getValue() == "4" || lc_busiClsCd.getValue() == "5") {
        $c.gus.cfDisableObjects([btn_corRegNo]);
    }
    //BIDC 이재설 과장, 최현주 대리 추가, 안재관 과장 추가
    if (scwin.g_AcctDeptCd == "00718" || scwin.g_AcctDeptCd == "00009" || scwin.vEmpNo == "198015" || scwin.vEmpNo == "198078" || scwin.vEmpNo == "198050" || scwin.vEmpNo == "171577") { 
        $c.gus.cfEnableObjects([lc_taxnCls, cbx_infoCollectYn, ed_jumin]);
        //$c.gus.cfDisableObjects( [lc_busiClsCd] ) ;
    } else {
        $c.gus.cfDisableObjects([lc_busiClsCd, lc_taxnCls, ed_crn, cbx_infoCollectYn, ed_jumin]);
    }
