/**
 * 사업자번호체크
 */
scwin.f_BizCheck = function() {
    // let row = ds_crn.getRowPosition();
    let row = gr_crn.getFocusedRowIndex();
    if (!$c.gus.cfIsNull(ed_crn.getValue())) {
        if ($c.gus.cfIsNull(lc_busiClsCd.getValue())) {
            // MSG_CM_ERR_002   = "@은(는) 필수 입력 항목입니다."
            $c.win.alert("사업자구분은(는) 필수 입력 항목입니다.");
            lc_busiClsCd.focus();
            return false;
        }

        //if ( gCorRegNoYn =="1" ) // 주민번호조회권한을 가지고있으면 법인번호 체크안한다.
        // return true
        // 사업자구분이 기타가 아닌경우 사업자 번호에 영문들어갈수 없음.
        if (lc_busiClsCd.getValue() != '4' && lc_busiClsCd.getValue() != "3") {
            var input = ed_crn.getValue();
            if (isNaN(input) == true) {
                $c.win.alert("사업자구분이 기타가 아닌경우 문자를 입력할수 없습니다.");
                return false;
            }
        }

        // 사업자구분이 주민등록 신고자가 아니고 사업자 번호가 주민등록 형식일 경우
        if (ed_crn.getValue().length == "13") {
            if (lc_busiClsCd.getValue() != "3") {
                var ju1 = ed_crn.getValue().substring(0, 6);
                var ju2 = ed_crn.getValue().substring(6, 13);

                if (scwin.check_jumin(ju1, ju2)) {
                    $c.win.alert("주민번호 형식의 사업자 번호 입니다.사업자구분을 주민등록 신고자로 선택하세요.");
                    ed_crn.focus();
                    return false;
                }
            }
        }

        // 법인사업자일 경우
        if (lc_busiClsCd.getValue() == "1") {
            if (ed_crn.getValue().length != "10") {
                $c.win.alert("법인사업자의 사업자번호는 10자리수로 입력하세요");
                return false;
            }

            if (ed_crn.getValue().trim().substring(3, 5) < 80 || ed_crn.getValue().trim().substring(3, 5) > 89) {
                $c.win.alert("법인사업자일경우 XX(123XX12345)는 80~89 사이에 있어야 합니다.");
                ed_crn.focus();
                return false;
            }

            // 법인사업자일 경우 법인번호는 필수입력
            if ($c.gus.cfIsNull(ed_corRegNo.getValue())) {
                var crnGubun = "N";
                // 팝업으로 열린 경우 법인번호 없이 입력가능
                if (!$c.util.isEmpty(scwin.valueObject)) {
                    crnGubun = scwin.valueObject["crnGubun"];
                }

                if (crnGubun == "Y") {

                } else {
                    $c.win.alert("법인사업자일 경우 법인번호는 필수입력입니다.");
                    return false;
                }
            }

            //법인번호체크 제외 권한자일 경우
            if (scwin.gCorRegNoCheck == "Y") {

            }else {
                //법인번호 체크여부에 체크되어 있을경우
                if (cbx_corRegNoYn.getValue() == "1" && $c.gus.cfIsNull(ed_corRegNo.getValue())) {
                    $c.win.alert("법인번호를 입력하세요");
                    return false;
                }else if (cbx_corRegNoYn.getValue() == "1" && !$c.gus.cfIsNull(ed_corRegNo.getValue())) {
                    if (!scwin.f_chkCorRegNo()) {
                        return false;
                    }
                }
            }
        }

        // 개인사업자일 경우
        if (lc_busiClsCd.getValue() == "2") {
            if (ed_crn.getValue().length != "10") {
                $c.win.alert("개인사업자의 사업자번호는 10자리수로 입력하세요");
                return false;
            }
            if (ed_crn.getValue().trim().substring(3, 5) > 79 && ed_crn.getValue().trim().substring(3, 5) < 90) {
                $c.win.alert("개인사업자일경우 XX(123XX12345)는 80~89 사이에 있으면 안됩니다.");
                ed_crn.focus();
                return false;
            }
            // 매출입구분이 매출혹은 공통인 경우 spy
            if (lc_busiPchsSellCls.getValue() == "1" || lc_busiPchsSellCls.getValue() == "3") { 
                if ($c.gus.cfIsNull(ed_corRegNo.getValue())) {
                    $c.win.alert("사업자구분이 개인사업자이고 매출입구분이 매출 혹은 공통인 경우 \n생년월일(YYMMDD)+성별(1~4)까지는 필수입력입니다.");
                    ed_corRegNo.focus();
                    return false;
                }

                var ju1 = ed_corRegNo.getValue().substring(0, 6);
                var ju2 = ed_corRegNo.getValue().substring(6, 13);
                var ju3 = ed_corRegNo.getValue().substring(0, 7);

                if (!scwin.check_birth(ju1, ju2)) {
                    $c.win.alert("사업자구분이 개인사업자이고 매출입구분이 매출 혹은 공통인 경우 \n생년월일(YYMMDD)+성별(1~4) 형태로 입력해 주세요.");
                    ed_corRegNo.focus();
                    return false;
                }
                //개인정보수집 불가로 생년월일(YYMMDD) + 성별 만 가져온다.
                ed_corRegNo.setValue(ju3);
            }
        }

        // 주민등록 신고자일 경우.
        if (lc_busiClsCd.getValue() == '3') {
            var ju1 = ed_crn.getValue().substring(0, 6);
            var ju2 = ed_crn.getValue().substring(6, 13);

            if (!scwin.check_birth(ju1, ju2)) {
                $c.win.alert("사업자구분이 주민등록신고자일 경우 생년월일(YYMMDD)+성별(1~4)까지는 필수입력입니다.");
                ed_crn.focus();
                return false;
            }

            // 개인정보수집여부 체크시에 주민번호 입력란에 필수입력
            if (cbx_infoCollectYn.getValue() == "1" && $c.gus.cfIsNull(ds_crn.getCellData(row, "decryptIdno1"))) {
                $c.win.alert("개인정보수집여부 체크 시 주민번호는 필수입력 입니다.");
                return false;
            }

            if (cbx_infoCollectYn.getValue() == "1") {
                if (ds_crn.getCellData(row, "decryptIdno1").length != '13') {
                    $c.win.alert("주민번호는 13자리로 입력하세요");
                    ed_jumin.focus();
                    return false;
                }
                var jumin1 = ed_crn.getValue().substring(0, 7);
                var jumin2 = ds_crn.getCellData(row, "decryptIdno1").substring(0, 7);

                if (jumin1 != jumin2) {
                    $c.win.alert("사업자번호의 앞 7자리와 주민번호의 앞 7자리가 다릅니다.");
                    return false;
                }

                var ju1 = ds_crn.getCellData(row, "decryptIdno1").substring(0, 6);
                var ju2 = ds_crn.getCellData(row, "decryptIdno1").substring(6, 13);

                if (!scwin.check_jumin(ju1, ju2)) {
                    $c.win.alert("올바른 주민등록번호 형식이 아닙니다.");
                    ed_jumin.focus();
                    return false;
                }
            }
        }

        // 기타일 경우
        if (lc_busiClsCd.getValue() == "4") {
            let ret = scwin.check_busino(ed_crn.getValue());
            if (ret) {
                $c.win.alert("사업자번호가 정상이므로 사업자구분을 기타로 선택 할 수 없습니다.확인바랍니다. ");
                return false;
            }

            if ($c.gus.cfIsNull(lc_etcBusiClsCd.getValue())) {
                $c.win.alert("사업자구분이 기타일 경우에 직원/외국인/DUNS/EORI등을 필수로 선택하셔야 합니다.");
                return false;
            }
        } else { //사업자구분이 그외일경우 과세구분 필수체크
            if ($c.gus.cfIsNull(lc_taxnCls.getValue())) {
                $c.win.alert("과세구분을 선택하셔야 합니다.");
                return false;
            }
        }

        // 재외국인등록 사업자일 경우
        if (lc_busiClsCd.getValue() == "5") {
            if (ed_crn.getValue().length != "10") {
                $c.win.alert("재외국인등록 사업자의 사업자번호는 10자리수로 입력하세요");
                return false;
            }
            if (ed_crn.getValue().trim().substring(3, 5) != 84) {
                $c.win.alert("재외국인등록 사업자일경우 XX(123XX12345)는84여야 합니다.");
                ed_crn.focus();
                return false;
            }
            scwin.f_check_fgnno();
        }
    }

    return true;

};


/**
 * 사업자번호체크(기타사업자용)
 */
scwin.check_busino = function (vencod) {
    var sum = 0;
    var getlist = new Array(10);
    var chkvalue = new Array("1", "3", "7", "1", "3", "7", "1", "3", "5");
    for (var i = 0; i < 10; i++) { getlist[i] = vencod.substring(i, i + 1); }
    for (var i = 0; i < 9; i++) { sum += getlist[i] * chkvalue[i]; }
    sum = sum + parseInt((getlist[8] * 5) / 10);
    sidliy = sum % 10;
    sidchk = 0;
    if (sidliy != 0) { sidchk = 10 - sidliy; }
    else { sidchk = 0; }
    if (sidchk != getlist[9]) { return false; }
    return true;
};


